    # ── CodeQL workflow ────────────────────────────────────────────────────────
    # Applied: all profiles — committed file artifact.
    # regulated profile adds SARIF artifact upload for audit evidence (90-day retention).
    # Docs: https://docs.github.com/en/code-security/code-scanning
    #
    # NOTE: GH Actions ${{ }} syntax is literal — no PowerShell variable interpolation.
    # Uses @'...'@ (single-quote here-string) for the static body; profile comment
    # is injected via -replace.

    $codeqlBody = @'
on:
  push:
    branches: [main, develop]
  pull_request:
    branches: [main]
  schedule:
    - cron: '0 2 * * 0'   # Weekly full scan: Sunday 02:00 UTC

permissions:
  contents: read
  security-events: write
  actions: read

jobs:
  analyze:
    name: Analyze (${{ matrix.language }})
    runs-on: ubuntu-latest

    strategy:
      fail-fast: false
      matrix:
        # Adjust to the languages in this repo.
        # Supported: c-cpp, csharp, go, java-kotlin, javascript-typescript,
        #            python, ruby, swift
        language: [javascript-typescript]

    steps:
      - name: Checkout repository
        uses: actions/checkout@v6

      - name: Initialize CodeQL
        uses: github/codeql-action/init@v4
        with:
          languages: ${{ matrix.language }}
          # queries: security-and-quality   # uncomment for extended query suite

      - name: Autobuild
        uses: github/codeql-action/autobuild@v4

      - name: Perform CodeQL Analysis
        uses: github/codeql-action/analyze@v4
        with:
          category: "/language:${{ matrix.language }}"
'@

    $evidenceStep = if ($RepoProfile -eq 'regulated') { @'

      # Upload SARIF as compliance evidence (regulated profile — 90-day retention)
      - name: Upload SARIF as compliance evidence
        if: always()
        uses: actions/upload-artifact@v4
        with:
          name: codeql-sarif-${{ github.run_id }}
          path: /home/runner/work/_temp/codeql_databases/
          retention-days: 90
'@ } else { '' }

    $codeqlWorkflow = "# CodeQL Analysis — applied by tech-github-repo-standards (profile: $RepoProfile)`n" +
                      "# Docs: https://docs.github.com/en/code-security/code-scanning`n`n" +
                      "name: CodeQL Analysis`n`n" +
                      $codeqlBody + $evidenceStep

    Invoke-UpsertFile -Repo $Repo `
        -Path '.github/workflows/codeql.yml' `
        -Message "ci: apply tech-github-repo-standards CodeQL workflow ($RepoProfile)" `
        -Content $codeqlWorkflow

    # ── Dependabot version-updates config ────────────────────────────────────
    # Enables scheduled dependency PRs alongside the security alerts/auto-fixes
    # that were enabled via the API. Detects common ecosystems; users should
    # remove unused entries or add ones for their stack.
    # Docs: https://docs.github.com/en/code-security/dependabot/dependabot-version-updates
    $dependabotYml = @'
# Dependabot version updates — applied by tech-github-repo-standards
# Docs: https://docs.github.com/en/code-security/dependabot/dependabot-version-updates/configuration-options-for-the-dependabot.yml-file
#
# Add or remove ecosystems below to match this repo. Common values:
#   npm, pip, gomod, maven, gradle, bundler, cargo, composer, nuget, docker
#
# `github-actions` is enabled below for every repo — workflows benefit from
# version pinning regardless of language.

version: 2
updates:
  - package-ecosystem: "github-actions"
    directory: "/"
    schedule:
      interval: "weekly"
    open-pull-requests-limit: 5
    labels:
      - "dependencies"
      - "ci"
    groups:
      # Batch all GitHub Actions bumps into a single weekly PR instead of
      # one PR per action. Avoids PR sprawl on fresh hardening runs where
      # several action versions are behind upstream.
      github-actions:
        patterns:
          - "*"

  # Uncomment and adjust for your primary language ecosystem:
  # - package-ecosystem: "npm"
  #   directory: "/"
  #   schedule:
  #     interval: "weekly"
  #   open-pull-requests-limit: 10
  #   groups:
  #     minor-and-patch:
  #       update-types: ["minor", "patch"]
  #   labels:
  #     - "dependencies"
'@

    Invoke-UpsertFile -Repo $Repo `
        -Path '.github/dependabot.yml' `
        -Message 'chore: apply tech-github-repo-standards Dependabot config' `
        -Content $dependabotYml
}

# ── Main ──────────────────────────────────────────────────────────────────────
function Main {
    Write-Host '================================================================'
    Write-Host ' GitHub Repository Standards'
    Write-Host " Context : $CONTEXT"
    Write-Host " Profile : $RepoProfile"
    Write-Host " Org     : $ORG"
    if ($DryRun) { Write-Host ' Mode    : DRY RUN — no changes will be made' -ForegroundColor Cyan }
    Write-Host '================================================================'
    Write-Host ''

    # Verify gh CLI is installed and authenticated
    gh auth status 2>$null | Out-Null
    if ($LASTEXITCODE -ne 0) {
        Write-Error 'ERROR: gh CLI is not authenticated. Run: gh auth login'
        exit 1
    }

    # Resolve repos (expand glob patterns)
    $allRepos = foreach ($r in $REPOS) {
        Resolve-Repos -Pattern $r
    }
    $allRepos = @($allRepos | Where-Object { $_ -ne '' })

    if ($allRepos.Count -eq 0) {
        Write-Error "ERROR: No repos found matching: $($REPOS -join ', ')`n       Check REPOS and verify org access: gh repo list $ORG"
        exit 1
    }

    Write-Host "Repos to configure ($($allRepos.Count)):"
    $allRepos | ForEach-Object { Write-Host "  $ORG/$_" }
    Write-Host ''

    foreach ($repo in $allRepos) {
        Write-Host '----------------------------------------------------------------'
        Write-Host " Configuring: $ORG/$repo"
        Write-Host '----------------------------------------------------------------'

        Apply-RepoSettings -Repo $repo
        Write-Host ''

        foreach ($branch in $PROTECTED_BRANCHES) {
            gh api "/repos/$ORG/$repo/branches/$branch" 2>$null | Out-Null
            if ($LASTEXITCODE -eq 0) {
                Apply-BranchProtection -Repo $repo -Branch $branch
            } else {
                Write-Host "> Branch '$branch' not found — skipping protection" -ForegroundColor Yellow
                Write-Host '  Create the branch first, then re-run this script.'
                $script:SettingsSkipped++
            }
            Write-Host ''
        }

        Apply-SecuritySettings -Repo $repo
        Write-Host ''

        Apply-ActionsSettings -Repo $repo
        Write-Host ''

        Apply-Access -Repo $repo
        Write-Host ''

        Commit-Artifacts -Repo $repo
        Write-Host ''
    }

    # ── Summary ───────────────────────────────────────────────────────────────
    Write-Host '================================================================'
    Write-Host ' Summary'
    Write-Host '================================================================'
    Write-Host " Context applied     : $CONTEXT"
    Write-Host " Profile applied     : $RepoProfile"
    Write-Host " Repos configured    : $($allRepos.Count)"
    Write-Host " Settings succeeded  : $($script:SettingsSucceeded)"
    Write-Host " Settings skipped    : $($script:SettingsSkipped)"
    Write-Host " Settings failed     : $($script:SettingsFailed)"
    Write-Host " Artifacts committed : $($script:ArtifactsCommitted)"
    Write-Host ''

    if ($script:ManualSteps.Count -gt 0) {
        Write-Host ' Manual steps required:'
        $script:ManualSteps | ForEach-Object { Write-Host "   * $_" -ForegroundColor Yellow }
        Write-Host ''
    }

    if ($RepoProfile -eq 'regulated') {
        Write-Host ' Regulated profile compliance checklist:'
        Write-Host '   [ ] Confirm NYDFS scope with legal/compliance'
        Write-Host '   [ ] Verify GitHub Advanced Security is licensed and enabled org-wide'
        Write-Host '   [ ] Enable org-level 2FA enforcement (org Settings -> Authentication security)'
        Write-Host '   [ ] Confirm audit log streaming is configured for the org'
        Write-Host '   [ ] Archive this script and generated artifacts as configuration evidence'
        Write-Host '   [ ] Schedule quarterly review of branch protection and access settings'
        Write-Host ''
    }

    if ($script:SettingsFailed -gt 0) {
        Write-Host " $($script:SettingsFailed) setting(s) failed. Review errors above before proceeding." -ForegroundColor Red
        exit 1
    } else {
        Write-Host ' All settings applied successfully.' -ForegroundColor Green
    }
}

Main
